VALUES
  ('social-worker-moex-01731', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '北歐的福利國家長期以來被視為國際間最高的社會福利標準，其福利國家模式大致有四個方向， 下列敘述何者錯誤？', '["強調社會分配的普遍性", "由私部門運作福利輸送系統", "社會供給重點在保護勞工", "社會福利的供給已經視為公民的基本權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01732', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為因應社會變遷，社會福利制度或政策也隨之變革，尤其是1980年代在嶄新自由主義的引導下 所做的改革，大致包括給付縮減及提高個人責任，下列敘述何者錯誤？', '["福利給付縮減包括提高法定給付年齡，減低老年給付水準及修改提早退休誘因", "對中高齡失業者提供請領殘障津貼作為提早請領退休給付的權宜作法", "非現金給付尤其是「稅式給付」受到重視，用以減少政府現金給付負擔", "推出工作福利及藉由福利促進就業，皆為提高個人責任的具體政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01733', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '近年來歐洲許多國家對於來自敘利亞及其他國家的難民收容方案，大都面臨困窘矛盾的狀況，對 於這些難民或是申請移民者出現壓力妥協的情況，英國對此提出了對策。下列敘述何者錯誤？', '["政府必須以國際認可的負責方式接受相當數量的難民，並歡迎這些人自由來去並申請公民身分 及國籍", "去除想要移民者的要求之合法性", "限制移民的就業機會、遷徙自由，包括取得福利服務在內的社會權利，以及追求家庭團圓的能力", "更廣泛的排除他們融入接受國社會的機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01734', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'Titmuss（1963）提出福利分工的概念，認為社會福利是由下列那三種提供體系相互調合？', '["社會福利、社會救助及社會保險", "政府福利、企業福利及志願服務", "社會福利、財稅福利及職業福利", "第一部門、第二部門及第三部門"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01735', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'Rose（1986）提出福利混合的概念，來說明不同福利輸送是否透過貨幣來進行區分為幾個類型。 下列何者錯誤？', '["市場主要透過貨幣進行輸送", "政府主要透過貨幣進行輸送", "家庭主要以非貨幣進行輸送", "社區主要透過貨幣進行輸送"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01736', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者是熊彼得式（schumpeterian）工作福利國家體制的特色？', '["充分就業", "開放式經濟體系與供給導向的政策", "普遍式的福利公民權", "市場與國家併行的混合經濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01737', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在福利混合經濟或福利多元主義模式中，商業部門參與社會服務的供給亦為其中之一環，下列何 者屬於其特色？', '["以「消費者為導向」的收費機制", "以「弱勢族群」為主要服務對象", "在社會公益的追求上與志願部門完全一樣", "提供去商品化的服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01738', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關「福利科層」的特性，下列敘述何者最正確？', '["在科層體系中，權力對應於科層體系中的位置", "其正當性來自於每次選舉所獲得的多數支持", "是一個非理性的決策運作系統", "強調個案處理的個別差異化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01739', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於「市場式治理」的敘述，下列何者錯誤？', '["是1980和1990年代興起的主流治理模式", "強調透過契約來輸送服務", "運用排行榜、監察及績效考核等辦法來責成管理者對組織績效負責", "此模式強調提供社區及全體人民有效的結果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01740', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助領取者的給付水準，下列敘述何者正確？', '["給付應以提供超過平均薪資以上的水準為目標", "給付應以提供超過基本薪資以上的水準為目標", "給付應以提供滿足基本生活需求的水準為目標", "給付應以提供薪資中位數的水準為目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
